#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAXN 100000
#define MAXL 101
#define HASH_SIZE 200003

typedef struct Node {
    char key[MAXL];
    int group;
    struct Node* next;
} Node;

Node* table[HASH_SIZE];
char words[MAXN][MAXL];
int group_head[MAXN];
int group_tail[MAXN];
int next_in_group[MAXN];
int group_cnt = 0;

unsigned long long fnv1a(const char *s){
    unsigned long long h = 1469598103934665603ULL;
    while(*s){
        h ^= (unsigned long long)(unsigned char)*s++;
        h *= 1099511628211ULL;
    }
    return h;
}

int cmp_char(const void *a, const void *b){
    return *(const char*)a - *(const char*)b;
}

int find_or_create(const char *key){
    unsigned long long h = fnv1a(key) % HASH_SIZE;
    Node *cur = table[h];
    while(cur){
        if(strcmp(cur->key, key) == 0) return cur->group;
        cur = cur->next;
    }
    Node *node = (Node*)malloc(sizeof(Node));
    strcpy(node->key, key);
    node->group = group_cnt;
    node->next = table[h];
    table[h] = node;
    group_head[group_cnt] = -1;
    group_tail[group_cnt] = -1;
    return group_cnt++;
}

void add_to_group(int gid, int idx){
    if(group_head[gid] == -1){
        group_head[gid] = group_tail[gid] = idx;
    } else {
        next_in_group[group_tail[gid]] = idx;
        group_tail[gid] = idx;
    }
    next_in_group[idx] = -1;
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    for(int tc=0; tc<T; ++tc){
        int N; scanf("%d", &N);
        for(int i=0;i<HASH_SIZE;++i) table[i]=NULL;
        group_cnt = 0;
        for(int i=0;i<N;++i){
            scanf("%s", words[i]);
            char key[MAXL];
            strcpy(key, words[i]);
            qsort(key, strlen(key), sizeof(char), cmp_char);
            int gid = find_or_create(key);
            add_to_group(gid, i);
        }
        for(int g=0; g<group_cnt; ++g){
            int idx = group_head[g];
            int first = 1;
            while(idx != -1){
                if(!first) printf(" ");
                printf("%s", words[idx]);
                first = 0;
                idx = next_in_group[idx];
            }
            printf("\n");
        }
        if(tc != T-1) printf("\n");
    }
    return 0;
}

