import sys

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    t = int(data[0].strip())
    idx = 1
    out_lines = []
    for tc in range(t):
        n = int(data[idx].strip()); idx += 1
        mp = {}
        order = []
        for _ in range(n):
            s = data[idx].strip(); idx += 1
            key = ''.join(sorted(s))
            if key not in mp:
                mp[key] = []
                order.append(key)
            mp[key].append(s)
        for k in order:
            out_lines.append(' '.join(mp[k]))
        if tc != t-1:
            out_lines.append('')
    sys.stdout.write('\n'.join(out_lines))

