  const N = parseInt(input[ptr++], 10);
  const map = new Map(); // key -> array of words
  const order = [];
  for (let i = 0; i < N; ++i) {
    const s = input[ptr++];
    const key = s.split('').sort().join('');
    if (!map.has(key)) {
      map.set(key, []);
      order.push(key);
    }
    map.get(key).push(s);
  }
  for (const k of order) {
    output.push(map.get(k).join(' '));
  }
  if (tc !== T - 1) output.push('');
}
